module RefModule(
    input clk,
    input load,
    input clear,
    input serial_in,
    input [7:0] data_in,
    output reg [7:0] q);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

		if (clear)
			q <= 8'b00000000;
		else if (load)
			q <= data_in;
		else
			q <= {q[6:0], serial_in};
	end
endmodule
